final:
module bcd_counter (
    input clk,
    input clear,
    output reg [3:0] bcd
);
always @(posedge clk) begin
    if (clear)
        bcd <= 4'b0000;
    else if (bcd == 4'b1001)
        bcd <= 4'b0000;
    else
        bcd <= bcd + 1;
end

  always @(*) begin
    if (1'b0) begin
      if (clear) begin
        bcd <= 4'b1111;
      end else if (bcd == 4'b0000) begin
        bcd <= 4'b1001;
      end
    end
  end

endmodule

